// cf-zero-trust.js — inject Cloudflare Access OAuth tokens as the
// "cf-access-token" header. Surge http-request + http-response script.
//
// Generated by zero-trust-auth-cli; do not edit by hand. The BOOTSTRAP map
// below is rewritten on every `zero-trust-auth-cli login` so the script is
// self-contained — no companion files, no `require()`.
//
// Flow (http-request):
//   1. Look up BOOTSTRAP[origin] for the request's origin (scheme://host).
//   2. Use the cached access_token in $persistentStore if it's still valid.
//   3. Otherwise POST the OAuth token_endpoint with grant_type=refresh_token,
//      cache the result, and inject "cf-access-token: <access_token>".
//
// Flow (http-response):
//   If the upstream replies 401 with WWW-Authenticate "invalid_token", drop
//   the cached entry for that origin so the next request triggers a refresh.

// __CF_ZERO_TRUST_BOOTSTRAP_BEGIN__ (auto-managed by `zero-trust-auth-cli login` — do not edit this block by hand)
const BOOTSTRAP = __CF_ZERO_TRUST_BOOTSTRAP__;
// __CF_ZERO_TRUST_BOOTSTRAP_END__

const STORE_PREFIX = "cf_zero_trust_";
const NOTIFY_PREFIX = "cf_zero_trust_notify_";
const NOTIFY_COOLDOWN_MS = 30 * 60 * 1000;
const SAFETY_MS = 30 * 1000;
const TIMEOUT_S = 5;

(function main() {
  // http-response branch: Surge sets $response when the script is wired up
  // as type=http-response. We don't modify the response — just invalidate
  // the cache when upstream rejected the injected token.
  if (typeof $response !== "undefined" && $response !== null) {
    handleResponse();
    return;
  }
  handleRequest();
})();

function handleRequest() {
  const reqURL = $request && $request.url;
  if (!reqURL) { $done({}); return; }
  const origin = originOf(reqURL);
  if (!origin) { $done({}); return; }

  const entry = BOOTSTRAP && BOOTSTRAP[origin];
  if (!entry || !entry.refresh_token || !entry.client_id || !entry.token_endpoint) {
    notifyOnce("bootstrap-missing:" + origin,
      "Cloudflare Access bootstrap missing for this origin",
      origin,
      "Run `zero-trust-auth-cli login " + origin + "` and reload the Surge module");
    $done({});
    return;
  }

  const cached = readCache(origin);
  const seedMatch = cached && cached.bootstrap_seed === entry.refresh_token;
  if (seedMatch && cached.access_token && cached.expires_at - SAFETY_MS > Date.now()) {
    console.debug("[cf-zero-trust] cache hit " + origin);
    inject(cached.access_token);
    return;
  }

  // Prefer the rotated refresh_token cached from a prior refresh, but only if
  // it was minted against the same bootstrap seed currently in this file. A
  // re-login (which mints a new refresh_token) invalidates the cache.
  const refreshToken = (seedMatch && cached.refresh_token) ? cached.refresh_token : entry.refresh_token;
  console.debug("[cf-zero-trust] cache miss " + origin + " — refreshing");
  refresh(origin, entry, refreshToken);
}

function handleResponse() {
  const reqURL = $request && $request.url;
  const origin = originOf(reqURL || "");
  const status = $response && ($response.status || $response.statusCode);
  if (!origin || status !== 401) { $done({}); return; }

  const wwwAuth = headerLookup($response.headers, "WWW-Authenticate") || "";
  // Only invalidate when the 401 is unmistakably from Cloudflare Access — not
  // from the upstream app, which may use its own OAuth realm and also reply
  // 401 with `error="invalid_token"`. Cloudflare Access's WWW-Authenticate
  // header always carries:
  //   resource_metadata="https://<host>/.well-known/cloudflare-access-protected-resource/..."
  // and an error code of invalid_token / expired_token.
  const fromCloudflareAccess = /cloudflare-access-protected-resource/i.test(wwwAuth);
  const tokenRejected = /invalid_token|expired_token/i.test(wwwAuth);
  if (!fromCloudflareAccess || !tokenRejected) {
    console.debug("[cf-zero-trust] 401 from " + origin +
      " not a Cloudflare Access token rejection — leaving cache alone");
    $done({});
    return;
  }

  console.debug("[cf-zero-trust] Cloudflare Access 401 — invalidating cache for " + origin);
  invalidateCache(origin);
  $done({});
}

function refresh(origin, entry, refreshToken) {
  const body =
    "grant_type=refresh_token" +
    "&refresh_token=" + encodeURIComponent(refreshToken) +
    "&client_id=" + encodeURIComponent(entry.client_id) +
    "&resource=" + encodeURIComponent(entry.resource || origin);

  $httpClient.post({
    url: entry.token_endpoint,
    headers: {
      "Accept": "application/json",
      "Content-Type": "application/x-www-form-urlencoded",
    },
    body: body,
    timeout: TIMEOUT_S,
  }, function (error, response, data) {
    if (error) {
      notifyOnce("refresh-network:" + origin,
        "Cloudflare Access refresh failed (network)",
        origin,
        String(error));
      $done({});
      return;
    }
    const status = response && response.status;
    if (!status || status >= 400) {
      notifyOnce("refresh-failed:" + origin,
        "Cloudflare Access token refresh failed",
        origin + " → HTTP " + status,
        "Re-run `zero-trust-auth-cli login " + origin + "`");
      $done({});
      return;
    }
    let t;
    try { t = JSON.parse(data); } catch (e) { $done({}); return; }
    if (!t || !t.access_token) { $done({}); return; }

    // Cloudflare normally returns expires_in (seconds). Fall back to 5 min so
    // a missing/zero value doesn't force us to hit the token endpoint on
    // every single request.
    const expiresInSec = Number(t.expires_in) > 0 ? Number(t.expires_in) : 300;
    writeCache(origin, {
      bootstrap_seed: entry.refresh_token,
      refresh_token: t.refresh_token || refreshToken,
      access_token: t.access_token,
      expires_at: Date.now() + expiresInSec * 1000,
    });
    clearNotify("bootstrap-missing:" + origin);
    clearNotify("refresh-failed:" + origin);
    clearNotify("refresh-network:" + origin);
    inject(t.access_token);
  });
}

function inject(accessToken) {
  const headers = Object.assign({}, ($request && $request.headers) || {}, {
    "cf-access-token": accessToken,
  });
  $done({ headers: headers });
}

function originOf(u) {
  const m = String(u).match(/^(https?:\/\/[^/?#]+)/i);
  return m ? m[1] : "";
}

function storeKey(origin) {
  // Surge persistent-store keys behave best as plain word characters.
  // Slashes and colons in origins like "https://x.example.com" can cause
  // writes to silently drop on some Surge versions.
  return STORE_PREFIX + String(origin).replace(/[^A-Za-z0-9]/g, "_");
}

function readCache(origin) {
  const key = storeKey(origin);
  const raw = $persistentStore.read(key);
  console.debug("[cf-zero-trust] readCache key=" + key +
    " raw=" + (raw ? raw.length + " bytes" : "null"));
  if (!raw) return null;
  try { return JSON.parse(raw); } catch (e) {
    console.debug("[cf-zero-trust] readCache JSON.parse failed: " + e);
    return null;
  }
}

function writeCache(origin, payload) {
  const key = storeKey(origin);
  const serialized = JSON.stringify(payload);
  const ok = $persistentStore.write(serialized, key);
  console.debug("[cf-zero-trust] writeCache key=" + key +
    " ok=" + ok +
    " bytes=" + serialized.length +
    " expires_at=" + payload.expires_at);
}

function invalidateCache(origin) {
  const key = storeKey(origin);
  // Surge `$persistentStore.write` with an empty value clears the key.
  const ok = $persistentStore.write("", key);
  console.debug("[cf-zero-trust] invalidateCache key=" + key + " ok=" + ok);
}

function headerLookup(headers, name) {
  if (!headers) return "";
  const lower = String(name).toLowerCase();
  for (const k in headers) {
    if (Object.prototype.hasOwnProperty.call(headers, k) && String(k).toLowerCase() === lower) {
      return headers[k];
    }
  }
  return "";
}

function notifyOnce(key, title, subtitle, body) {
  const k = NOTIFY_PREFIX + key;
  const last = parseInt($persistentStore.read(k) || "0", 10);
  const now = Date.now();
  if (last && now - last < NOTIFY_COOLDOWN_MS) return;
  if (typeof $notification !== "undefined" && $notification.post) {
    $notification.post(title, subtitle, body || "");
  }
  $persistentStore.write(String(now), k);
}

function clearNotify(key) {
  $persistentStore.write("", NOTIFY_PREFIX + key);
}
